## Tipos de accidente más frecuentes


::: {.cell}

```{.r .cell-code}
if (!is.null(atus_ml)) {
  accidentes_tipo_top <- atus_ml |> count(TIPACCID, name = "n") |> slice_max(n, n = 10)
  ggplot(accidentes_tipo_top, aes(x = reorder(TIPACCID, n), y = n)) +
    geom_col(fill = col_azul, width = 0.75) +
    coord_flip() +
    scale_y_continuous(labels = etiqueta_numero) +
    labs(title = "Tipos de accidente más frecuentes", x = "Tipo de accidente", y = "Número de accidentes") +
    tema_libro()
}
```

::: {.cell-output-display}
![](03-analisis-exploratorio_files/figure-html/unnamed-chunk-8-1.png){width=768}
:::
:::


## Proporción por tipo de accidente


::: {.cell}

```{.r .cell-code}
if (!is.null(atus_ml)) {
  tipos_top <- atus_ml |> count(TIPACCID) |> slice_max(n, n = 10) |> pull(TIPACCID)
  atus_tipo_top <- atus_ml |> filter(TIPACCID %in% tipos_top)
  ggplot(atus_tipo_top, aes(x = TIPACCID, fill = accidente_con_victimas)) +
    geom_bar(position = "fill") +
    coord_flip() +
    escala_clases_fill() +
    scale_y_continuous(labels = etiqueta_porcentaje) +
    labs(title = "Proporción de accidentes con víctimas según tipo de accidente", x = "Tipo de accidente", y = "Proporción", fill = "Clase") +
    tema_libro()
}
```

::: {.cell-output-display}
![](03-analisis-exploratorio_files/figure-html/unnamed-chunk-9-1.png){width=768}
